BEGIN;

INSERT INTO public.template (slug, version, name, description, metadata, blocks)
VALUES (
  'exit-readiness-teaser-v1',
  1,
  'Exit Readiness Teaser (Mandanten-Report)',
  'V8 Mandanten-adressierter Selbstcheck mit deterministischem SUI-Score ueber 11 Module (M0..M10).',
  jsonb_build_object(
    'usage_kind',          'mandanten_report_teaser_v1',
    'scoring_kind',        'sui_weighted',
    'report_renderer',     'mandanten_report_v2',
    'gewichtung',          '{"m1":10,"m2":10,"m3":10,"m4":10,"m5":10,"m6":10,"m7":10,"m8":10,"m9":20}'::jsonb,
    'stufen_lookup',       '{"m1":{"s1":{"was_es_bedeutet":"Jedes Mandat / jedes Projekt / jeder Auftrag ist eine Sonderloesung. Es gibt kein wiederholbares Standardprodukt. Was die Firma macht, ist im Wesentlichen, was der Inhaber persoenlich kann. Neue Mitarbeiter brauchen Jahre, bis sie eigenstaendig liefern koennen — wenn ueberhaupt. Auf der Webseite und in Angeboten ist nicht klar, was die Firma als Standard liefert.","unsere_empfehlung":"Das ist Ihr groesster strategischer Engpass. So wie heute kann die Firma nicht uebergeben werden — sie wuerde auseinanderfallen, sobald Sie weg sind. Das ist nicht in 3 Monaten zu loesen, das ist ein 12-18-Monats-Projekt. Aber es ist machbar, und es ist der wichtigste Hebel ueberhaupt. Erster konkreter Schritt: definieren Sie in 1-2 Saetzen, was Ihr Standardprodukt eigentlich ist — und ueberpruefen Sie, ob 3 Mitarbeiter es gleich beantworten wuerden."},"s2":{"was_es_bedeutet":"Es gibt erste Ideen, die Kernleistung zu standardisieren. Vielleicht ein erster Versuch eines Standard-Angebots, eine Webseite mit dem Versuch eines klaren Leistungs-Versprechens. Aber in der Realitaet ist immer noch jedes Projekt anders. Mitarbeiter wissen nicht genau, wo die Standard-Grenze endet und die Individualisierung beginnt. Es bestehen mehr Sonder-Konditionen als Standard-Konditionen.","unsere_empfehlung":"Sie sind auf dem richtigen Weg, aber das Tempo reicht nicht. Nageln Sie Ihr Standardprodukt schriftlich fest — als 1-2-Saetze-Definition, die Sie und 3 Mitarbeiter gleich beantworten wuerden. Solange diese Definition nicht steht, bleibt Standardisierung Wunschdenken. Konkreter naechster Schritt: Standard-Definition in einem 90-Minuten-Workshop mit Ihren Schluessel-Mitarbeitern erarbeiten und gegenzeichnen lassen."},"s3":{"was_es_bedeutet":"Es gibt ein definiertes Standardprodukt, das auch im Markt so kommuniziert wird. Vielleicht 60-70% der Auftraege laufen tatsaechlich als Standard. Aber die restlichen 30-40% sind weiter Sonder-Anpassungen, und der Inhaber ist meistens dort beteiligt. Neue Mitarbeiter brauchen noch 6-12 Monate bis zur eigenstaendigen Lieferung. Die Alleinstellungs-Merkmale sind zwar definiert, werden aber im Vertriebs-Alltag nicht konsequent genutzt.","unsere_empfehlung":"Hier laeuft schon einiges richtig. Aber die letzten 30% sind die teureren — das sind die Margen-Killer und die Inhaber-Abhaengigkeits-Punkte. Zwei konkrete Schritte: erstens, definieren Sie klare Kriterien, wann ein Auftrag als Sonder-Anpassung gilt (und was er dann kostet); zweitens, arbeiten Sie die naechsten 1-2 Mitarbeiter so ein, dass sie auf Stufe 4 kommen — Standard ohne Sie ausliefern koennen."},"s4":{"was_es_bedeutet":"80-90% des Geschaefts laeuft als wiederholbares Standardprodukt. Der Inhaber ist in der Lieferung nicht mehr operativ noetig. Neue Mitarbeiter werden in 3-6 Monaten produktiv. Die Alleinstellungs-Merkmale sind im Markt erkennbar — Kunden koennen sie konkret benennen (\"Bei euch ist das anders, weil...\"). Sonder-Anpassungen gibt es noch, aber sie sind selten und werden bewusst angenommen, nicht zufaellig.","unsere_empfehlung":"Das ist solide aufgestellt. Ein Kaeufer wuerde sagen: ja, das ist ein uebergebbares Produkt. Pruefen Sie jetzt eher, ob die letzten 10-20% noch optimierbar sind — oder ob Sie die Zeit besser in andere Module investieren, in denen Sie noch bei Stufe 2 oder 3 stehen. Marginal-Return-Entscheidung."},"s5":{"was_es_bedeutet":"Die Kernleistung laeuft als reproduzierbare Produkt-Realitaet ohne Inhaber-Beteiligung. Vom ersten Kunden-Kontakt bis zur Lieferung ist der Prozess dokumentiert, von Mitarbeitern getragen und mit klaren Qualitaets-Indikatoren versehen. Skalierung ist nicht Theorie, sondern praktisch gezeigt: die Firma hat im letzten Jahr 30% mehr Volumen abgewickelt ohne 30% mehr Aufwand. Neue Mitarbeiter sind in 2-3 Monaten produktiv. Die Alleinstellungs-Merkmale sind nicht nur erkennbar, sondern werden im Vertrieb auch aktiv eingesetzt und reproduzieren sich.","unsere_empfehlung":"Das ist vorzeigbar. Wenn morgen ein strategischer Kaeufer kaeme — das hier ist Bewertungs-Multiplikator-treibend. Investieren Sie keine weitere Zeit in diesen Block, nutzen Sie die Energie fuer die schwaecheren Module."}},"m2":{"s1":{"was_es_bedeutet":"Es wird angenommen, was reinkommt — egal ob es zum Geschaeftsmodell passt oder nicht. Die Marge pro Kunde ist unbekannt. Niemand kann zwischen wirtschaftlich starken und schwachen Kunden konkret unterscheiden. „Wir koennen die nicht einfach gehen lassen\" ist die Standardantwort, wenn die Trennung von schwachen Kunden zur Sprache kommt. Es gibt 2-3 Schluesselkunden, die zusammen mehr als 40% des Umsatzes ausmachen, und das wird als Staerke wahrgenommen, nicht als Risiko.","unsere_empfehlung":"Sie navigieren im Blindflug — und ein Kaeufer wird das als hohes Risiko bewerten, weil er nicht weiss, was an Ihrer Kundenbasis eigentlich tragfaehig ist. Erster konkreter Schritt: eine Auswertung der Marge je Top-20-Kunde im letzten Jahr. Erst wenn Sie sehen, welcher Kunde Sie wirklich finanziert und welcher nur Aufwand macht, koennen Sie steuernd eingreifen."},"s2":{"was_es_bedeutet":"Es gibt eine Idee davon, welche Kunden „gut laufen\" und welche „nerven\". Aber das ist Bauchgefuehl, nicht datenbasiert. Eine erste Marge-pro-Kunde-Auswertung wurde vor 1-2 Jahren gemacht, aber nicht systematisch fortgefuehrt. Ein erstes Ideal-Kundenprofil ist im Kopf vorhanden, aber nicht aufgeschrieben und nicht in der Akquise verankert. Trennung von schlechten Kunden findet nicht statt — auch wenn Sie wissen, dass Sie es eigentlich tun sollten.","unsere_empfehlung":"Sie wissen schon, was problematisch ist. Aber wissen alleine reicht nicht. Nageln Sie das Ideal-Kundenprofil schriftlich fest (3-5 Kriterien, nicht mehr) und treffen Sie eine bewusste Entscheidung, von welchen 2-3 schwachen Kunden Sie sich in den naechsten 6 Monaten konsequent trennen. Das ist emotional schwer, aber wirtschaftlich oft der groesste einzelne Hebel."},"s3":{"was_es_bedeutet":"Marge pro Kunde wird mindestens jaehrlich ausgewertet. Es gibt ein definiertes Ideal-Kundenprofil, das auch in der Akquise eine Rolle spielt. Erste Trennungen von schwachen Kunden haben stattgefunden — vielleicht 1-3 Faelle in den letzten 12 Monaten. Die Abhaengigkeit von Schluesselkunden ist erkannt, aber noch nicht reduziert: der groesste Kunde steht weiterhin bei 25-30% Umsatzanteil.","unsere_empfehlung":"Hier laeuft schon Disziplin rein. Aber die Schluesselkunden-Abhaengigkeit ist noch da. Das ist fuer einen Kaeufer einer der wichtigsten Risiko-Punkte — er rechnet einen \"Klumpen-Risiko-Abschlag\" von 10-20% direkt in den Kaufpreis. Konkreter Plan: 18-24-Monats-Plan, wie Sie den Top-Kunden-Anteil systematisch unter 20% bringen — entweder durch gezieltes Wachstum in andere Kunden oder durch bewusste Diversifizierung."},"s4":{"was_es_bedeutet":"Marge je Kunde ist transparent und steuerbar. Ideal-Kundenprofil ist im Vertrieb verankert — neue Kunden werden bewusst danach gefiltert. Kunden ausserhalb des Profils werden mit Sonder-Preisen angenommen oder freundlich abgelehnt. Trennung von schwachen Kunden ist Routine, nicht Ausnahme. Schluesselkunden-Anteil ist auf 15-20% maximal reduziert. Die Kundenbasis ist als ausgewogenes Portfolio bewusst gestaltet.","unsere_empfehlung":"Das ist solide. Ein Kaeufer wuerde das als stabile Kundenbasis bewerten. Pruefen Sie jetzt eher, ob es einzelne Kundensegmente gibt, in denen Sie wachsen wollen — die Energie geht jetzt in Wachstum, nicht mehr in Aufraeumen. Marginal-Return-Entscheidung pro Segment."},"s5":{"was_es_bedeutet":"Die Kundenbasis ist als strategisches Asset bewusst gestaltet und gesteuert. Marge pro Segment wird quartalsweise nachverfolgt. Kein einzelner Kunde macht mehr als 12-15% des Umsatzes aus. Ideal-Kundenprofil wird jaehrlich ueberprueft und angepasst. Trennung von schwachen Kunden ist Teil der jaehrlichen Strategie — und die Vertriebs-Mitarbeiter handeln danach. Es gibt eine bewusste Pipeline-Strategie, welche Wunsch-Kunden in den naechsten 12 Monaten gewonnen werden sollen.","unsere_empfehlung":"Das ist vorbildlich. Ein Kaeufer sieht hier ein steuerbares, niedrig-Risiko Portfolio. Investieren Sie keine weitere Energie in dieses Modul — bewahren Sie nur die Routine."}},"m3":{"s1":{"was_es_bedeutet":"Zahlen sind das, was einmal im Jahr beim Jahresabschluss kommt. Es gibt keine eigenen Kennzahlen, keine monatlichen Reports, keine aktive Steuerung. Zahlungsziele sind lang (60+ Tage), Anzahlungen werden nicht gefordert. Die Reserve liegt unter zwei Monaten Auszahlungsbedarf. Wenn ein Schluesselkunde 30 Tage spaeter zahlt, wird es eng. Margen pro Produkt oder Bereich sind unbekannt — Sie haben ein Bauchgefuehl, mehr nicht.","unsere_empfehlung":"Hier muss als Erstes Liquiditaet stabilisiert werden, sonst koennen Sie ueber strukturelle Themen gar nicht reden. Konkrete erste Schritte: Zahlungsziele kuerzen, Anzahlungen einfuehren, eine 3-Monats-Reserve aufbauen. Parallel ein einfaches monatliches Reporting mit 5 Kennzahlen, das Sie in 10 Minuten lesen koennen. Das ist nicht Komfort, das ist Ueberlebens-Hygiene."},"s2":{"was_es_bedeutet":"Es gibt einen Monatsabschluss oder ein einfaches eigenes Reporting. Die wichtigsten Zahlen sind bekannt, aber rueckblickend, nicht steuernd. Reserven liegen bei 2-3 Monaten Auszahlungs-Bedarf. Zahlungsziele werden langsam reduziert, aber unsystematisch. Margen pro Produkt sind grob bekannt, aber nicht differenziert. Fruehindikatoren fuer Schwierigkeiten gibt es nicht — Probleme werden erst sichtbar, wenn sie schon da sind.","unsere_empfehlung":"Die Grundausstattung ist da. Aber Sie steuern noch reaktiv, nicht vorlaufend. Bauen Sie das Berichtswesen so um, dass es Frueh-Indikatoren liefert: wie sich der Auftragseingang im Vergleich zum Vormonat entwickelt, welche Marge der laufende Monat erwartet, wie der 12-Wochen-Liquiditaets-Forecast aussieht. Das macht den Unterschied zwischen Ueberraschungen und Steuerung."},"s3":{"was_es_bedeutet":"Es gibt ein monatliches Reporting mit 5-8 Kennzahlen, das Sie tatsaechlich anschauen. Reserve liegt bei 3-4 Monaten. Zahlungsziele sind auf 30 Tage gesenkt, Anzahlungen sind Standard bei groesseren Auftraegen. Margen pro Hauptbereich sind bekannt und werden besprochen. Erste Fruehindikatoren werden beobachtet — etwa Auftragseingang, Pipeline-Volumen, Marge-Trend. Aber die Auswertung ist meist manueller Aufwand (Excel, einmal im Monat zusammengeklickt), und Sie sind die einzige Person, die das wirklich versteht.","unsere_empfehlung":"Solide Grundlage. Die naechsten Schritte: das Reporting so automatisieren, dass es ohne Ihren persoenlichen Aufwand entsteht — und dass eine zweite Person im Unternehmen die Zahlen genauso lesen kann wie Sie. Das ist auch ein Stellvertreter-Thema, nicht nur ein Zahlen-Thema."},"s4":{"was_es_bedeutet":"Reporting ist automatisiert und liegt monatlich auf dem Tisch — Sie lesen es, aber Sie produzieren es nicht. Reserve liegt bei 4-6 Monaten, das ist bewusst gesteuert. Zahlungsziele und Forderungs-Management funktionieren ohne Ihren Eingriff. Margen pro Produkt, pro Kunde, pro Region sind transparent. Fruehindikatoren werden monatlich besprochen und triggern bei Abweichungen automatisch eine Reaktion. Der CFO oder eine vergleichbare Rolle ist installiert und tragfaehig.","unsere_empfehlung":"Das ist exakt das, was ein Kaeufer sehen will. Hier kann er einsteigen und in drei Wochen verstehen, wie die Firma wirtschaftlich tickt. Keine weitere Strukturarbeit noetig — Reports nur sauber konsolidiert halten, falls noch mehrere parallel laufen."},"s5":{"was_es_bedeutet":"Zahlen-Steuerung ist eine Routine, kein Projekt. Monatliche Reports werden in der Geschaeftsleitung gemeinsam besprochen, nicht nur von Ihnen gelesen. 12-Monats-Forecasts werden regelmaessig aktualisiert und stimmen typischerweise auf 5% genau. Reserve liegt bei 6+ Monaten und ist Teil einer bewussten Kapital-Strategie. Margen-Steuerung ist vorlaufend: bevor ein Bereich Marge verliert, wird gegengesteuert. Die Firma ist wirtschaftlich nicht nur stabil, sondern auch erklaerbar — jede Veraenderung im letzten Jahr laesst sich auf konkrete Entscheidungen zurueckfuehren.","unsere_empfehlung":"Das ist vorzeigbar. Ein Finanz-Investor wuerde hier 1-2 Multiple-Punkte mehr zahlen, weil die wirtschaftliche Steuerbarkeit klar ist. Sie sind hier auf dem Spitzen-Niveau — bewahren und pflegen."}},"m4":{"s1":{"was_es_bedeutet":"Vertrieb = Sie persoenlich. Praktisch jeder relevante Geschaeftsabschluss laeuft persoenlich ueber Sie. Schluesselkunden kennen niemand anders. Preise werden ad-hoc verhandelt, ohne Logik. Lead-Pflege ist eine Notiz im Notizbuch. Angebote werden von Hand neu geschrieben. KI-Tools sind im Vertrieb nicht im Einsatz — vielleicht spielt ein Mitarbeiter privat mit ChatGPT, aber das ist keine Vertriebs-Faehigkeit der Firma.","unsere_empfehlung":"Das ist neben Modul 1 der zweite kritische Punkt fuer Ihre Uebergabe-Faehigkeit. So wie heute kann niemand Sie ersetzen — der Vertrieb geht mit Ihnen weg. Konkreter 12-18-Monats-Plan: erstens die Pricing-Logik dokumentieren, zweitens 1-2 Vertriebs-Mitarbeiter mit echtem Mandat aufbauen, drittens KI-Tools fuer Lead-Recherche und Angebots-Entwuerfe systematisch einfuehren. Das geht parallel, nicht nacheinander."},"s2":{"was_es_bedeutet":"Es gibt ein erstes Vertriebs-Team, aber Sie sind bei wichtigen Abschluessen weiterhin dabei. Pricing-Logik ist in Ihrem Kopf, wird aber langsam dokumentiert. Erste CRM-Eintraege existieren, aber sind unvollstaendig. Vereinzelte Mitarbeiter haben ChatGPT/Claude im Buero ausprobiert, aber es gibt keine systematische KI-Nutzung im Vertriebs-Prozess. Lead-Recherche und Angebots-Entwuerfe laufen weiter manuell.","unsere_empfehlung":"Es laeuft was an, aber das Tempo reicht nicht. Definieren Sie konkret: welche Vertriebs-Aufgabe wollen Sie in den naechsten 90 Tagen aus Ihrer Hand wegbekommen? Und parallel: welche 1-2 KI-Werkzeuge bringen Sie produktiv in den Vertrieb (Lead-Recherche-Tool, KI-gestuetzte Angebots-Vorlagen)? Beides muss sichtbar Fortschritt machen, sonst verfestigt sich das alte Muster."},"s3":{"was_es_bedeutet":"40-60% der Geschaeftsabschluesse laufen ohne Sie. Es gibt eine dokumentierte Pricing-Logik, aber Sonderfaelle gehen weiterhin ueber Sie. CRM ist im Einsatz und wird gepflegt. Erste KI-Tools sind produktiv im Vertrieb: vielleicht ChatGPT/Claude fuer Angebots-Entwuerfe, ein Lead-Research-Tool fuer Recherche, eine Auswertungs-Pipeline mit KI-Zusammenfassungen. Aber: nicht systematisch, nicht skalierbar, kein einheitlicher Standard ueber alle Mitarbeiter.","unsere_empfehlung":"Sie sind im richtigen Korridor. Die naechsten Schritte: erstens, die letzten 30-40% Inhaber-Abhaengigkeit konkret angehen — welche Schluesselkunden bestehen noch auf Sie persoenlich, was muss passieren um diese Beziehung zu uebertragen? Zweitens, KI-Einsatz im Vertrieb standardisieren: nicht jeder Mitarbeiter macht es anders, sondern es gibt einen klaren Pool an Tools und Workflows, der fuer alle gilt."},"s4":{"was_es_bedeutet":"80%+ der Geschaeftsabschluesse laufen ohne Sie. Pricing-Logik ist transparent, dokumentiert und wird von Vertriebs-Mitarbeitern selbststaendig angewandt. CRM ist vollstaendig und steuert tatsaechlich den Vertriebs-Prozess. KI-Tools sind im Vertriebs-Alltag verankert: standardisierte Lead-Recherche-Workflows, KI-gestuetzte Angebots-Entwuerfe, automatisierte Kunden-Kommunikation an passenden Stellen, KI-Auswertungen ueber Pipeline und Conversion. Schluesselkunden haben Vertretungs-Beziehungen aufgebaut.","unsere_empfehlung":"Sehr gut. Ein Kaeufer wuerde sagen: der Vertrieb ist als Prozess uebergebbar. Investieren Sie jetzt in die letzten 10-20% — vor allem die verbleibenden Inhaber-Schluesselkunden-Beziehungen und das Feinjustieren der KI-Tools (welche bringen Effekt, welche sind nur Show)."},"s5":{"was_es_bedeutet":"Vertrieb laeuft als professioneller Prozess komplett ohne Sie. 95%+ der Geschaeftsabschluesse werden vom Team gemacht. Pricing-Logik wird quartalsweise ueberprueft und angepasst. KI-Einsatz im Vertrieb ist Standard und differenziert: Lead-Research, Angebots-Erstellung, Cross-/Up-Sell-Empfehlungen, Pipeline-Forecasting, Kunden-Kommunikation — alles dort, wo es Mehrwert bringt, und bewusst nicht dort, wo persoenliche Beziehung zaehlt. Das Vertriebs-Team kann KI-Tools selbststaendig einsetzen und weiterentwickeln. Sie sind nur noch bei strategisch wichtigen Schluesselkunden-Terminen praesent — und auch dort als Sparring, nicht als Verkaeufer.","unsere_empfehlung":"Das ist Spitzen-Niveau. Ein strategischer Kaeufer wuerde hier deutlich mehr zahlen, weil der Vertrieb nachweislich skaliert und nicht inhaber-abhaengig ist. Halten Sie das Niveau, mehr ist nicht noetig."}},"m5":{"s1":{"was_es_bedeutet":"Praktisch der gesamte Umsatz ist Projekt-Umsatz oder Einzeltransaktionen. Es gibt keine Wartungs-Vertraege, keine Abonnements, keine Lizenz-Modelle, keine Service-Vertraege. Beim Neukunden-Abschluss wird nie ein Folge-Vertrag angeboten. Recurring-Anteil liegt bei unter 5%. Das wird nicht als Problem gesehen — „wir leben halt von Projekten\".","unsere_empfehlung":"Das ist eine der einfachsten und gleichzeitig groessten Hebel fuer Ihre Bewertung. Ueberlegen Sie, welche Recurring-Komponente zu Ihrem Geschaeftsmodell passt — Wartungs-Vertrag, jaehrliche Pruefung, Subscription, Lizenz, Service-Vertrag. Auch wenn Sie nur 20% Recurring erreichen, vervielfacht das den Bewertungs-Multiple bei diesen 20%. Das ist eine 12-Monats-Aufgabe mit grossem wirtschaftlichen Effekt."},"s2":{"was_es_bedeutet":"Es gibt ein erstes Recurring-Modell — vielleicht Wartungs-Vertraege oder eine kleine Subscription. Aber es ist nicht systematisch in den Vertrieb integriert. Bei Neukunden-Abschluessen wird das Recurring-Angebot manchmal erwaehnt, manchmal vergessen. Der Recurring-Anteil liegt bei 5-15%. Die Preisgestaltung des Recurring-Modells ist unklar oder uninteressant gemacht — Kunden sehen wenig Anreiz dort einzusteigen.","unsere_empfehlung":"Sie haben angefangen, aber das Tempo reicht nicht. Das Recurring-Modell muss erstens preislich attraktiv sein (so dass der Kunde Sinn darin sieht), zweitens automatisch beim Neukunden-Abschluss angeboten werden (nicht optional), drittens systematisch in bestehende Kunden hineinverkauft werden. Ohne diese drei Bewegungen bleibt es beim Symbol-Niveau."},"s3":{"was_es_bedeutet":"Recurring-Modelle sind etabliert und sichtbar. Der Recurring-Anteil liegt bei 15-30% des Gesamtumsatzes. Bei Neukunden-Abschluessen wird das Recurring-Angebot regelmaessig mitverkauft. Es gibt erste Up-Sell-Aktivitaeten in bestehende Kunden. Aber: die Erneuerungsraten werden nicht systematisch gemessen, und Kundenbindung passiert eher beilaeufig als gesteuert.","unsere_empfehlung":"Solider Stand. Die naechsten Schritte: Erneuerungsraten messen und steuern (ein verlorener Recurring-Kunde ist 3-5x teurer als ein verlorener Projekt-Kunde), Up-Sell-Pfade systematisch in den Vertriebs-Prozess einbauen, und das Recurring-Angebot bewusst weiterentwickeln (verschiedene Stufen, Premium-Optionen)."},"s4":{"was_es_bedeutet":"Recurring-Anteil liegt bei 30-50% des Gesamtumsatzes. Erneuerungsraten werden monatlich gemessen und sind tragfaehig (90%+). Es gibt mehrere Recurring-Stufen, die zu unterschiedlichen Kunden passen. Up-Sell und Cross-Sell in bestehende Kunden ist Routine. Die Preisgestaltung ist bewusst kalkuliert — Recurring rechnet sich fuer den Kunden, ist aber auch fuer die Firma marge-stark.","unsere_empfehlung":"Sehr gut. Ein Kaeufer wuerde sich diese Recurring-Basis genau ansehen und positiv bewerten. Stellen Sie jetzt nur noch sicher, dass die Verlaufsdaten (12-18 Monate Erneuerungsraten, Churn-Verlauf, durchschnittlicher Recurring-Wert pro Kunde) sauber dokumentiert sind. Das ist das, was den Multiple wirklich anhebt."},"s5":{"was_es_bedeutet":"Recurring ist das Rueckgrat des Geschaefts. 50%+ des Umsatzes sind wiederkehrend. Erneuerungsraten liegen ueber 95%, Churn ist quartalsweise transparent. Es gibt eine bewusste Recurring-Strategie mit klaren Stufen, Up-Sell-Pfaden und langfristigen Kunden-Lifecycle-Werten. Neue Mitarbeiter werden auf den Recurring-Verkauf trainiert. Die Firma kann mit hoher Sicherheit 12-18 Monate vorausplanen, weil die Recurring-Basis stabil ist.","unsere_empfehlung":"Das ist genau das, was ein Finanz-Investor zu Recurring-Multiples bringt. Dieser Block treibt Ihre Bewertung erheblich nach oben. Investieren Sie keine weitere Strukturarbeit hier — bewahren und ausbauen."}},"m6":{"s1":{"was_es_bedeutet":"Daten sind verteilt auf mehrere unsynchronisierte Systeme (CRM, ERP, Excel, E-Mail-Postfaecher, Papier-Akten). Doppelte und widerspruechliche Stammdaten sind die Regel. Kennzahlen muessen manuell zusammengeklickt werden — wenn ueberhaupt. KI-Tools spielen keine Rolle — vielleicht hat ein Mitarbeiter privat ChatGPT ausprobiert, aber keiner weiss, was die anderen tun. Es gibt keine Datenstrategie, keine KI-Strategie und niemanden, der das Thema verantwortet.","unsere_empfehlung":"Das ist ein doppelter Engpass: erstens die Datenstruktur, zweitens der KI-Einsatz. Ein Kaeufer rechnet beides als Investitions-Bedarf direkt aus dem Kaufpreis raus. Starten Sie zwei Spuren parallel: Datenkonsolidierung (welche 3-5 Systeme sind kritisch, wo sind die schmerzhaftesten Doppel-Eintraege) und einen ersten KI-Use-Case (etwa Reporting-Automatisierung, Kunden-Kommunikation, Angebots-Entwuerfe). Beides nicht als Mega-Projekt, sondern als sichtbarer Erst-Schritt in 90 Tagen."},"s2":{"was_es_bedeutet":"Es gibt ein zentrales CRM oder ERP, das meiste laeuft dort. Aber Excel-Insel-Loesungen sind weiter im Einsatz, vor allem fuer Reporting und Spezial-Faelle. Stammdaten sind zu 70-80% gepflegt. Erste KI-Tools werden privat von einzelnen Mitarbeitern genutzt (ChatGPT/Claude im Buero-Alltag), aber es gibt keinen kontrollierten Daten-Pfad und niemanden, der einen Ueberblick hat, was wo gemacht wird.","unsere_empfehlung":"Sie sind nicht ganz unten. Aber das Setup ist fragil. Reduzieren Sie erstens die Excel-Insel-Loesungen (welche koennen ins CRM/ERP integriert werden), zweitens definieren Sie eine bewusste Position zum KI-Einsatz — wer darf welche Tools nutzen, mit welchen Daten, wie wird das nachgehalten. Sonst wird das ein Wildwuchs, der gefaehrlich wird."},"s3":{"was_es_bedeutet":"Daten liegen ueberwiegend strukturiert in 1-2 Hauptsystemen. Kennzahlen sind schnell abrufbar. Erste produktive KI-Einsaetze sind etabliert in 1-2 Bereichen — etwa KI-gestuetzte Auswertungen, ChatGPT/Claude fuer interne Texte, ein Buchhaltungs-Tool mit KI-Funktionen. Es gibt einen losen Ueberblick, welche Tools im Einsatz sind. Zufriedenheit mit den eingesetzten Tools ist gemischt — manche bringen Effekt, andere sind eher Show.","unsere_empfehlung":"Mittelfeld, mit Tendenz nach oben. Die naechsten Schritte: eine bewusste Auswahl, welche KI-Tools strategisch sein sollen (nicht jeder probiert was anderes), die Datenbasis fuer diese Tools nochmal pruefen (was an Daten brauchen die Tools, wie sauber ist das), und die Zufriedenheits-Frage ehrlich beantworten — wo bringen die Tools heute schon messbaren Effekt, wo nur Aufwand?"},"s4":{"was_es_bedeutet":"Daten sind konsolidiert, strukturiert und exportierbar. Reporting und Kennzahlen-Steuerung laufen automatisiert. KI-Tools sind produktiv in mehreren Bereichen im Einsatz (Vertrieb, Reporting, Kunden-Kommunikation, Buchhaltung, Marketing) — nicht alle, aber dort wo sie konkret Nutzen bringen. Zufriedenheit mit den Tools ist hoch, weil die Auswahl bewusst und passend zum Geschaeft erfolgt ist. Es gibt einen verantwortlichen Mitarbeiter oder Teilfunktion, die KI-Themen begleitet.","unsere_empfehlung":"Das ist solide aufgestellt. Ein Kaeufer wuerde das positiv bewerten — Sie sind nicht „voll bei KI\", aber Sie nutzen die Hebel, die zu Ihrem Geschaeft passen. Beobachten Sie jetzt nur noch, dass das Niveau gehalten wird und neue, wirklich nuetzliche Tools nicht uebersehen werden — das ist ein Continuous-Learning-Thema."},"s5":{"was_es_bedeutet":"Die Datenbasis ist KI-ready in jeder relevanten Dimension — strukturiert, dokumentiert, exportierbar, zugriffsklar. KI-Tools sind quer durch die operativen Bereiche im produktiven Einsatz, mit klaren Workflows, Verantwortlichkeiten und messbaren Resultaten (Margen-Hebung, Zeit-Ersparnis, Qualitaets-Verbesserung). Zufriedenheit mit den Tools ist hoch und differenziert — nicht jedes Hype-Tool wird gekauft, sondern bewusst ausgewaehlt. Es gibt einen klaren KI-Verantwortlichen und einen 12-Monats-KI-Plan (siehe auch Modul 9), der aktiv umgesetzt wird.","unsere_empfehlung":"Das ist auf Spitzen-Niveau. Ein strategischer Kaeufer oder Finanz-Investor wuerde das als zukunfts-tauglich bewerten — und das kommt im Multiple sichtbar an. Sie sind hier ein Branchen-Vorreiter."}},"m7":{"s1":{"was_es_bedeutet":"Es gibt keine Dokumentation. Das gesamte operative Wissen lebt in Ihrem Kopf und in den Koepfen von 2-3 Schluessel-Mitarbeitern. Wenn jemand eine ungewoehnliche Kundenanfrage hat, fragt er Sie. Wenn ein neuer Mitarbeiter kommt, lernt er durch Zuschauen, nicht durch Lesen. Die Aussage „das machen wir bei diesem Kunden so\" hat eine Geschichte, die niemand mehr wirklich kennt — auch Sie nicht immer.","unsere_empfehlung":"Das ist das groesste Risiko ueberhaupt fuer Ihre Uebergabe-Faehigkeit. Wenn Sie morgen 6 Wochen ausfallen, ist der wirtschaftliche Schaden moeglicherweise massiv — nicht weil die Mitarbeiter nichts koennen, sondern weil das spezifische Wissen nicht abrufbar ist. Beginnen Sie mit einem strukturierten Wissens-Capture — die ersten 10 wichtigsten Entscheidungs-Muster dokumentieren, dann iterativ ausbauen. Das ist ein 12-18-Monats-Projekt, aber jeder Monat zaehlt, weil das Wissen nicht juenger wird."},"s2":{"was_es_bedeutet":"Es gibt einzelne Prozess-Beschreibungen — vielleicht ein Onboarding-Dokument fuer neue Mitarbeiter, eine FAQ-Liste im Wiki, einige SOPs fuer wiederkehrende Aufgaben. Aber das ist Stueckwerk: 80-90% des operativen Wissens ist weiter nicht dokumentiert. Das Wissen, das dokumentiert ist, wird kaum gepflegt — der letzte Stand ist 1-2 Jahre alt.","unsere_empfehlung":"Sie haben angefangen. Aber das Tempo reicht nicht, und vor allem die Pflege ist nicht etabliert. Gehen Sie einerseits in die Tiefe (Entscheidungs-Logik, nicht nur Prozesse), andererseits etablieren Sie ein System fuer die laufende Pflege. Sonst entsteht Dokumentation, die sofort wieder veraltet."},"s3":{"was_es_bedeutet":"Es gibt ein zentrales Wissenssystem (Wiki, SharePoint, ein dediziertes Tool). 40-60% der operativen Prozesse sind dokumentiert. Ein neuer Mitarbeiter kann die wichtigsten Standard-Themen nachlesen. Aber: die Tiefe fehlt. Entscheidungs-Logik („warum entscheiden wir bei diesem Kunden so?\") ist meist nicht dokumentiert. Ausnahme-Behandlung („das machen wir bei diesem Lieferanten anders\") lebt weiter im Kopf. Die Aktualisierung passiert sporadisch, ohne klaren Owner.","unsere_empfehlung":"Solide Basis. Jetzt geht es um zwei Dinge: erstens, die Entscheidungs-Logik und die Ausnahme-Faelle dokumentieren (das ist das wirklich wertvolle Wissen, nicht die Standard-Prozesse). Zweitens, einen Verantwortlichen fuer die laufende Pflege benennen — ohne klaren Owner faellt das ueber Zeit auseinander. Wenn Sie diese zwei Punkte loesen, kommen Sie auf Stufe 4."},"s4":{"was_es_bedeutet":"70-85% des operativen Wissens ist abrufbar dokumentiert — nicht nur Prozesse, sondern auch Entscheidungs-Logik, Kunden-Historien, Ausnahme-Behandlung. Ein Vertreter kann typische Kundenfragen ohne Inhaber-Anruf beantworten. Neue Mitarbeiter werden in 3-4 Monaten produktiv (statt 12+). Die Pflege ist als Routine etabliert — es gibt Verantwortliche pro Wissensbereich, und Updates passieren regelmaessig.","unsere_empfehlung":"Sehr gut. Ein Kaeufer wuerde sagen: ja, das Wissen ist uebertragbar. Gehen Sie jetzt noch die letzten 15-25% an — vor allem die wirklich versteckten Wissens-Inseln, die nur einzelne Schluessel-Mitarbeiter im Kopf haben. Diese gezielt mit strukturierten Capture-Sessions herausziehen."},"s5":{"was_es_bedeutet":"Das Unternehmerhandbuch ist substantiell und gepflegt. Praktisch jedes operative Wissen ist abrufbar — von Prozess-Schritten ueber Entscheidungs-Logik bis zu Kunden-Historien und Lieferanten-Erfahrungen. Es ist als System aufgebaut, das nicht nur Menschen lesen koennen, sondern auch eine KI durchsuchen und nutzen kann. Die Aktualisierung ist Teil des operativen Alltags — jede neue Erkenntnis wird zeitnah eingespeist. Ein neuer Mitarbeiter ist in 6-10 Wochen produktiv. Bei einer Uebergabe wuerde der Nachfolger eine echte Wissens-Basis vorfinden, kein Stueckwerk.","unsere_empfehlung":"Das ist genau das, was Strategaize als zentralen Hebel betont — und Sie haben es geschafft. Das ist Multiple-treibend und ueberbietet locker die Branchen-Standards. Bewahren und pflegen, mehr ist nicht noetig."}},"m8":{"s1":{"was_es_bedeutet":"Sie sind der einzige operative Engpass. „Frag mal den Chef\" ist die Standard-Antwort fuer alles. Stellvertreter existieren nicht oder sind formal benannt aber ohne echtes Mandat. Schluessel-Mitarbeiter haben keine Vertretung. Konflikte werden von Ihnen persoenlich geloest. Interne Kommunikation laeuft ueber das Inhaber-Drehkreuz. Mitarbeiter wissen nicht, wo sie Antworten finden — sie fragen direkt Sie. Neue Mitarbeiter brauchen 6-12 Monate bis zur produktiven Arbeit. KI-Verantwortung gibt es nicht — wenn ueberhaupt, beschaeftigen Sie sich selbst damit, mit den ueblichen „kommt-nie-dazu\"-Resultaten.","unsere_empfehlung":"Hier liegt einer der groessten Hebel ueberhaupt. So wie heute kann die Firma weder uebergeben werden, noch koennen Sie ein konkretes Sabbatical von drei Wochen einplanen ohne sichtbares Risiko. Starten Sie mit einer klaren Stellvertreter-Struktur (wer entscheidet was, wenn Sie nicht da sind), parallel mit einem KI-Verantwortlichen (auch als 20%-Teilfunktion eines existierenden Mitarbeiters)."},"s2":{"was_es_bedeutet":"Stellvertreter sind benannt, aber haben in der Praxis kaum Mandat. Es gibt erste interne Kommunikations-Tools (Wiki, Chat-Programm), aber sie werden nicht konsequent genutzt. Mitarbeiter-Aufbau ist reaktiv. Ein Mitarbeiter hat sich „so nebenbei\" mit KI-Tools beschaeftigt — aber das ist eine Privatangelegenheit, keine offizielle Verantwortung.","unsere_empfehlung":"Sie haben angefangen, aber die Strukturen sind noch zerbrechlich. Konkret: das Stellvertreter-Mandat muss echt sein (Stellvertreter darf wirklich entscheiden, nicht nur „koennte theoretisch\"). Und die KI-Verantwortung muss formal werden — etwa 20% einer Stellenbeschreibung eines bestehenden Mitarbeiters, mit klarem Auftrag und Reporting. Sonst bleibt es bei guten Vorsaetzen."},"s3":{"was_es_bedeutet":"Stellvertreter haben in 60-70% der Faelle echtes Mandat. Mitarbeiter wissen, wer wofuer zustaendig ist. Interne Kommunikation laeuft ueber definierte Kanaele. Mitarbeiter-Aufbau ist halbwegs systematisiert (Onboarding-Plan, definierte erste 90 Tage). Ein KI-Verantwortlicher existiert formal, hat aber wenig Mandat oder Zeit. Sie sind in den meisten wichtigen Sitzungen immer noch dabei.","unsere_empfehlung":"Solide Mitte. Die naechsten Schritte: erstens, nehmen Sie sich bewusst aus 2-3 Routine-Sitzungen raus, in denen Sie nicht beitragen muessen. Zweitens, nehmen Sie den KI-Verantwortlichen ernst — der braucht Zeit (mindestens halben Tag pro Woche), Budget fuer Tools und einen klaren Plan, was er in den naechsten 12 Monaten erreichen soll."},"s4":{"was_es_bedeutet":"Stellvertreter sind funktionsfaehig, der operative Betrieb laeuft ohne Sie. Entscheidungswege sind klar und dokumentiert. Interne Kommunikation funktioniert ohne Inhaber-Drehkreuz. Mitarbeiter-Aufbau ist systematisiert, neue Mitarbeiter werden in 3-4 Monaten produktiv. Es gibt einen klaren KI-Verantwortlichen mit dediziertem Mandat (Teilzeit-Funktion oder eigene Rolle), der KI-Initiativen treibt und ueber Resultate berichtet. Konflikt-Loesung passiert mehrheitlich auf Team-Ebene.","unsere_empfehlung":"Das ist sehr gut. Ein Kaeufer wuerde sagen: das Fuehrungsteam ist tragfaehig, das KI-Thema ist verankert. Gehen Sie sich die letzten 10-15% Inhaber-Drehkreuz-Momente vor — meist sind das alte Routinen, die ohne Sie genauso laufen wuerden."},"s5":{"was_es_bedeutet":"Die Firma laeuft auch bei laengerer Inhaber-Abwesenheit (3 Monate Sabbatical, Krankheit) stabil weiter. Stellvertreter haben Mandat, treffen Entscheidungen, sind ansprechbar fuer Mitarbeiter. Es gibt eine klare Karriere-Logik im Team, Recruiting und Onboarding sind systematisch aufgebaut. KI-Verantwortung ist eine etablierte Rolle mit Strategie, Budget und Resultaten — wenn der KI-Verantwortliche morgen ausfaellt, gibt es eine Vertretung, weil das Wissen dokumentiert ist. Interne Kommunikation funktioniert auf mehreren Ebenen ohne Sie.","unsere_empfehlung":"Das ist Spitzen-Niveau. Ein Kaeufer sieht hier eine echt uebergebbare Organisation. Sie sind hier raus aus dem Optimierungs-Modus — das ist bewahren und pflegen."}},"m9":{"s1":{"was_es_bedeutet":"Veraenderungen werden geplant, aber nicht beendet. Das Tagesgeschaeft drueckt jede strukturelle Arbeit weg. Es gibt keine wiederkehrenden Reviews oder Retrospektiven. Veraenderungs-Initiativen werden als „Projekt\" gestartet und nach 4-6 Wochen fallen gelassen. Mitarbeiter werden in Veraenderungen nicht ausreichend mitgenommen. Eine strategische Position zum Thema KI gibt es nicht — vielleicht eine vage Vorstellung „wir muessen uns da mal mit beschaeftigen\". KI-Initiativen stehen seit Monaten „auf der Liste\" ohne konkreten Verantwortlichen, ohne naechsten Meilenstein.","unsere_empfehlung":"Das ist der wichtigste Engpass, den Sie loesen muessen. Sie koennen in den Modulen 1-8 ueberall sehr gut werden — wenn Modul 9 nicht funktioniert, halten die Verbesserungen nicht. Drei konkrete Schritte: erstens ein einfaches Rhythmus-Tool einfuehren (monatliches Review: was haben wir umgesetzt, was nicht, warum), zweitens eine klare Position zu KI fuer die Zukunft Ihrer Firma reflektieren, drittens einen ersten konkreten KI-Projekt-Plan fuer die naechsten 90 Tage definieren — mit Verantwortlichem, naechstem Meilenstein, Start-Termin."},"s2":{"was_es_bedeutet":"Es gibt erste Versuche, Veraenderungen systematisch zu treiben — etwa quartalsweise Strategie-Termine oder eine Liste mit „dringenden Projekten\". Aber die Umsetzungs-Quote ist gering: 20-40% der gestarteten Initiativen werden tatsaechlich abgeschlossen. Eine erste Position zum Thema KI ist formuliert („wir wollen KI nutzen\") — aber ohne konkrete Konsequenzen fuer Investitionen, Mitarbeiter oder Geschaeftsmodell. Ein KI-Plan existiert als Liste, ist aber eher Wunschdenken als Roadmap.","unsere_empfehlung":"Es bewegt sich was, aber das Tempo reicht nicht. Erhoehen Sie die Umsetzungs-Quote spuerbar — das beginnt damit, weniger Initiativen gleichzeitig zu starten und die, die laufen, konsequenter zu Ende zu bringen. Und der KI-Plan muss vom Wunsch zum Plan werden: was sind die naechsten 3-5 konkreten Schritte, wer verantwortet sie, bis wann sind sie umgesetzt."},"s3":{"was_es_bedeutet":"Es gibt eine etablierte Rhythmus-Struktur fuer strukturelle Arbeit — etwa monatliche Reviews, quartalsweise Strategie-Termine. Umsetzungs-Quote liegt bei 50-65%. Eine klare strategische Position zum Thema KI ist formuliert und im Fuehrungsteam besprochen. Ein 12-Monats-KI-Plan existiert mit konkreten Projekten — erste sind angefangen, aber noch nicht alle stark unterwegs. Mitarbeiter werden in Veraenderungen aktiv mitgenommen.","unsere_empfehlung":"Solide. Sie sind im richtigen Korridor. Nutzen Sie die naechsten 6 Monate, um die Umsetzungs-Quote auf 75-85% zu bringen — das ist meistens eine Frage der Prioritaeten (weniger gleichzeitig starten, mehr zu Ende bringen). Und der KI-Plan muss konkrete Resultate liefern, nicht nur Projekt-Starts — was hat sich messbar veraendert?"},"s4":{"was_es_bedeutet":"Strukturelles Wertschaffen ist Routine. Veraenderungen werden mit klaren Outcomes geplant, umgesetzt und 6-12 Monate spaeter noch nachweisbar in Kraft. Umsetzungs-Quote liegt bei 75-90%. Die strategische KI-Position ist im Fuehrungsteam verankert und beeinflusst konkrete Entscheidungen (Investitionen, Mitarbeiter-Profile, Tool-Auswahl). Der 12-Monats-KI-Plan ist konkret, hat Verantwortliche, naechste Meilensteine in <30 Tagen, und es gibt messbare Resultate aus laufenden Projekten. Mitarbeiter-Veraenderungen werden aktiv begleitet.","unsere_empfehlung":"Sehr gut. Das ist genau das, was Bewertungs-Multiple anhebt. Ein Kaeufer sieht hier eine Firma, die Veraenderungen wirklich umsetzt und KI aktiv adressiert. Halten Sie das Niveau, das ist der wichtigste Block."},"s5":{"was_es_bedeutet":"Strukturelles Wertschaffen ist Identitaet der Firma, nicht Projekt. Veraenderungen werden konsequent umgesetzt, gehalten und beweisbar mit Resultaten dokumentiert (12-18 Monate Verlaufsdaten). Die strategische KI-Position ist existenziell verankert — das Fuehrungsteam und die Mitarbeiter wissen, was KI fuer die Zukunft der Firma bedeutet, und es gibt konkrete Konsequenzen in Investitionen, Mitarbeiter-Profilen und Geschaeftsmodell. Der KI-Plan ist eine rollende 12-Monats-Roadmap, die quartalsweise ueberprueft und aktualisiert wird. Mitarbeiter-Veraenderungen werden vorausschauend gehandhabt.","unsere_empfehlung":"Das ist auf Spitzen-Niveau. Modul 9 ist im SUI doppelt gewichtet, und Sie sind hier oben — das treibt Ihren Gesamt-Score erheblich. Ein Finanz-Investor oder strategischer Kaeufer wuerde hier deutlich hoehere Multiples zahlen, weil die Firma nachweislich umsetzungsstark und zukunfts-tauglich ist."}}}'::jsonb,
    'worum_es_geht',       '{"m1":"Eine Firma wird verkaufbar, wenn ihre Kernleistung wiederholbar ist — von anderen Menschen, in anderen Situationen, ohne den Inhaber. Ein massgeschneidertes Genie-Produkt, das nur der Inhaber selbst liefern kann, ist keine verkaufbare Firma, sondern ein schwer uebergebbarer Job. Wer eine Firma kauft, kauft die Faehigkeit, das Produkt **in Zukunft** zu liefern — nicht die Vergangenheit des Inhabers.","m2":"Nicht jeder Kunde ist ein guter Kunde. Wer alle Anfragen annimmt, baut Komplexitaet, die das skalierbare Modell zerstoert. Margenschwache Kunden, Schluesselkunden mit Sonderwuenschen, „schon-immer-Kunden\" mit eingewachsenen Sonder-Konditionen — sie alle ziehen die Firma in Richtungen, die ein Kaeufer als Risiko bewertet. Ein konsequenter Kunden-Fokus ist die Voraussetzung dafuer, dass die Firma wirklich skalierbar bleibt und Sie als Inhaber Spielraum zurueck bekommen.","m3":"Liquiditaet ist King. Wer seine Zahlen nicht aktiv steuert, kann nicht uebergeben — weil der Nachfolger blind in eine Black Box steigen muesste. Ein Kaeufer will sehen: kurze Zahlungsziele, transparente Kennzahlen, frueh erkannte Schwierigkeiten, klare Margen pro Bereich. Wer diese Substanz nicht hat, verliert nicht nur beim Verkauf — er steuert seine Firma jeden Tag mit dem Risiko, dass ein kleiner Schluck (verzoegerte Zahlung, ausgefallener Kunde) gleich zum Problem wird.","m4":"Wenn Sie persoenlich verkaufen muessen, ist die Firma nicht uebergebbar. Top-Kunden bestehen auf Inhaber-Kontakt, Preise haengen an Ihrem Bauchgefuehl, Verhandlungen werden von Ihnen gefuehrt — bei einer Uebergabe geht all das mit Ihnen weg. Vertrieb muss strukturierter, dokumentierter und delegierbarer Prozess werden. Plus heute, im KI-Zeitalter: ein moderner Vertrieb nutzt KI-Tools in der Lead-Recherche, der Angebots-Erstellung und der Auswertung — wer das nicht tut, verschenkt Hebel und wirkt fuer einen Kaeufer veraltet.","m5":"Wiederkehrende Umsaetze (Wartung, Subscription, Lizenz, Service-Vertraege, regelmaessige Lieferungen) sind der staerkste Bewertungs-Multiplikator. Ein Kaeufer zahlt fuer einen Euro Recurring-Revenue typischerweise 3-5x mehr als fuer einen Euro Projekt-Umsatz. Das ist nicht Theorie — es ist die direkteste Stellschraube zwischen heute und einem deutlich hoeheren Verkaufspreis. Plus: wiederkehrende Umsaetze geben Ihnen Planungssicherheit, machen die Firma weniger anfaellig fuer Marktschwankungen, und sie erlauben es, in Wachstum zu investieren statt bei jedem Quartalsende zu hoffen.","m6":"Eine Firma wird in den naechsten 5-10 Jahren nicht mehr nach „laeuft sie?\" bewertet, sondern nach „kann sie KI sinnvoll einsetzen?\". Die Antwort darauf haengt nicht primaer an installierter KI-Software, sondern an der Voraussetzung davor: **strukturierte Daten und sauber organisierte Prozesse, mit denen Sie KI ueberhaupt anstossen koennen.** Plus die zweite Schicht: welche KI-Tools sind heute schon produktiv im Einsatz, in welchen Bereichen, und wie zufrieden sind Sie damit. Wer hier weit hinten ist, wird beim Verkauf abgewertet, weil der Kaeufer den Aufholbedarf direkt einkalkuliert.","m7":"Strategaize-Kernstaerke und gleichzeitig der Punkt, an dem die meisten Inhaber-gefuehrten Firmen wirklich verlieren wuerden. Das Tagesgeschaefts-Wissen — warum bestellen Sie bei diesem Lieferanten, wie reagieren Sie auf diese typische Kundenanfrage, was tun Sie wenn dieser Maschinen-Typ ausfaellt, warum haben Sie diesem Kunden vor 5 Jahren Sonder-Konditionen gegeben — lebt in Ihrem Kopf. Wenn Sie morgen ausfallen oder die Firma uebergeben, geht dieses Wissen mit. Ein Kaeufer kauft eine Firma ohne diese Substanz nicht — oder zahlt deutlich weniger.","m8":"Der gesamte Betrieb muss ohne Sie laufen — nicht nur Vertrieb. Das umfasst Entscheidungswege, Mitarbeiter-Aufbau, Konflikt-Loesung, interne Kommunikation und Stellvertreter-Strukturen. Plus heute eine neue Dimension: wer im Team treibt das Thema KI? Wenn KI bei Ihnen haengen bleibt und Sie das nebenbei machen, faellt es bei der ersten Belastung weg. Wer KI-Verantwortung im Team verankert, hat eine andere Substanz.","m9":"Eine Firma verkaufsbereit zu machen ist kein Drei-Monats-Projekt. Die 8 vorherigen Module beschreiben, **was** veraendert werden sollte. Modul 9 misst, ob Sie die Veraenderungen, die Sie als notwendig erkennen, auch **tatsaechlich umsetzen — und ob diese Umsetzungen ueber 6+ Monate stabil halten.** Plus zwei spezifische KI-Dimensionen, die hier zusammenkommen: die strategische Position zum Thema KI fuer die zukuenftige Wettbewerbsfaehigkeit der Firma, und die Konkretheit des 12-Monats-KI-Plans."}'::jsonb,
    'hausaufgaben_lookup', '{"M0.1":{"teilweise":"Ein paar zentrale Vertraege liegen weiter als physische Akten oder sind seit Jahren nicht angepasst. Setzen Sie sich in den naechsten 90 Tagen einen Termin: alle Top-20-Vertraege durchgehen, fehlende digital erfassen, abgelaufene Klauseln aktualisieren. Das ist nicht teuer, aber es braucht einen Anwalt-Termin und 1-2 strukturierte Tage interner Aufwand.","nein":"Das ist die kritischste Baustelle in diesem Block. Bei einer Due Diligence wuerde ein Kaeufer hier sofort einen Bewertungs-Abschlag setzen. Bevor Sie ueber operative Verbesserungen oder Verkauf nachdenken, muss diese strukturelle Hausaufgabe gemacht werden — sonst ist der spaetere Aufwand Schall und Rauch. Konkreter Plan: Anwalt-Mandat fuer Vertrags-Inventur in den naechsten 30 Tagen anstossen, 12-18 Monate Bearbeitungs-Zeitraum einplanen."},"M0.2":{"teilweise":"Einiges ist sauber registriert, aber 1-2 wichtige Positionen haengen noch privat oder sind unklar zugeordnet. Klaeren Sie das in den naechsten 6 Monaten: welche Marken/Patente/Domains muessen ueberschrieben werden, welche Lizenzen umgemeldet. Das ist meistens ein 2-3-Termin-Vorgang mit einem IP-Anwalt — nicht teuer, aber notwendig.","nein":"Wenn geistiges Eigentum nicht auf der Firma liegt, ist die Firma im Verkaufs-Fall faktisch unvollstaendig. Ein Kaeufer kauft, was er nicht uebernehmen kann. Das muss vor allen anderen strukturellen Verbesserungen geklaert werden. Konkreter Plan: IP-Anwalt-Mandat in den naechsten 30 Tagen, vollstaendige Uebertragung in 6-12 Monaten — mit klaren steuerlichen Konsequenzen, die ein Berater begleiten muss."},"M0.3":{"teilweise":"Die meisten Vertraege bestehen, aber Klauseln sind veraltet oder fehlen bei 1-2 wichtigen Positionen. Ueberpruefen Sie in den naechsten 90 Tagen, welche 3-5 Schluessel-Mitarbeiter aktualisierte Vertraege brauchen, und sprechen Sie die Nachverhandlung als Routine-Update an — nicht als Krisen-Signal.","nein":"Ohne aktuelle Vertraege mit Wettbewerbs- und Kunden-Schutz-Klauseln kann ein Schluessel-Mitarbeiter die Firma jederzeit mit Kunden, Wissen und Know-How verlassen. Ein Kaeufer sieht das sofort als zentrales Risiko. Konkreter Plan: Anwalt-Vorlagen erstellen lassen, Reihenfolge nach Risiko-Hoehe priorisieren (welcher Mitarbeiter koennte den groessten Schaden anrichten), in 12 Monaten alle Top-5-Positionen abgeschlossen."},"M0.4":{"teilweise":"Sie haben einen Ueberblick, aber 1-2 Altverpflichtungen sind seit Jahren nicht ueberprueft worden. Setzen Sie sich in den naechsten 3 Monaten mit Ihrer Bank zusammen, alle laufenden Buergschaften auflisten, pruefen welche reduziert oder abgeloest werden koennen. Vor jedem Verkaufs-Szenario muss klar sein, welche persoenlichen Risiken bestehen — und ob sie zwingend persoenlich bleiben muessen.","nein":"Persoenliche Buergschaften, die nicht aktiv gesteuert werden, sind das groesste persoenliche Risiko fuer einen Inhaber 50+. Im Verkaufs-Fall hindern sie ausserdem die saubere Trennung Inhaber–Firma. Konkreter Plan: Bank-Termin zur vollstaendigen Inventur in den naechsten 30 Tagen, Reduktions-Plan ueber 12-24 Monate, ggf. Umstellung auf gewerbliche Sicherheiten anstelle privater Buergschaft."},"M0.5":{"teilweise":"Die meisten Pflichten werden erfuellt, aber die Dokumentation ist unvollstaendig oder veraltet. Setzen Sie in den naechsten 6 Monaten einen einmaligen Compliance-Aufraeum-Termin: Datenschutz-Konzept aktualisieren, Branchen-Vorgaben-Liste pruefen, Aufzeichnungs-Pflichten klaeren. Das ist meistens 2-3 Tage Aufwand mit einem Fachberater — kein Drama, aber notwendig.","nein":"Compliance-Luecken sind in der Due Diligence besonders teuer: jeder Mangel wird vom Kaeufer mit einem Bewertungs-Abschlag und einem Garantie-Vorbehalt belegt. Konkreter Plan: Compliance-Beratungs-Termin in den naechsten 60 Tagen anstossen, vollstaendige Bestandsaufnahme, 12-Monats-Hausaufgaben-Plan — meist parallel zu anderen rechtlichen Themen abzuarbeiten."}}'::jsonb
  ),
